using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ---------------------------------------------------------------
    // CalculateTotal – [DataRow] for compile-time-constant scenarios
    // ---------------------------------------------------------------

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10 % tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8 % tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "100 % tax rate")]
    public void CalculateTotal_ReturnsExpectedResult(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        // DataRow only supports primitive types; cast to decimal inside the test.
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ---------------------------------------------------------------
    // CalculateTotal – [DynamicData] for invalid-argument scenarios
    // ---------------------------------------------------------------

    public static IEnumerable<object[]> InvalidCalculateTotalInputs
    {
        get
        {
            yield return new object[] { -1m,  1,  0.1m, "unitPrice",  "Negative unit price" };
            yield return new object[] {  10m, -1, 0.1m, "quantity",   "Negative quantity" };
            yield return new object[] {  10m,  1, -0.1m, "taxRate",   "Negative tax rate" };
            yield return new object[] {  10m,  1, 1.5m,  "taxRate",   "Tax rate above 1" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalInputs))]
    public void CalculateTotal_InvalidInput_ThrowsArgumentOutOfRangeException(
        decimal unitPrice, int quantity, decimal taxRate,
        string expectedParamName, string scenario)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName, $"Scenario: {scenario}");
    }

    // ---------------------------------------------------------------
    // ApplyDiscount – [DataRow] for happy-path combinations
    // ---------------------------------------------------------------

    [TestMethod]
    [DataRow(100.00, 0.0,   100.00, DisplayName = "0 % discount")]
    [DataRow(100.00, 10.0,  90.00,  DisplayName = "10 % discount")]
    [DataRow(100.00, 50.0,  50.00,  DisplayName = "50 % discount")]
    [DataRow(100.00, 100.0, 0.00,   DisplayName = "100 % discount")]
    [DataRow(49.99,  20.0,  39.992, DisplayName = "Fractional price, 20 % discount")]
    [DataRow(0.00,   25.0,  0.00,   DisplayName = "Zero price, 25 % discount")]
    public void ApplyDiscount_ReturnsExpectedResult(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ---------------------------------------------------------------
    // ApplyDiscount – [DynamicData] with a static method source
    // ---------------------------------------------------------------

    public static IEnumerable<object[]> InvalidDiscountInputs()
    {
        yield return new object[] { 100m, -1m,   "Below 0" };
        yield return new object[] { 100m, 100.01m, "Above 100" };
        yield return new object[] { 100m, 200m,  "Far above 100" };
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountInputs), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRangeException(
        decimal price, decimal discountPercent, string scenario)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName, $"Scenario: {scenario}");
    }
}

